  "api.1password.com": {"domain":"api.1password.com","display_name":"1Password Connect","auth_type":"api_key","portal_url":"https://my.1password.com/integrations/connect","steps":["Go to https://my.1password.com/integrations/connect","Sign in to your 1Password account (requires a 1Password Teams or Business plan)","Click 'Add a Connect Server'","Give your Connect server a name and select which vaults it can access","Download the 1password-credentials.json file — this is used to run the Connect server","Click 'Issue Token' and give the token a name and set an expiration (30, 90, or 180 days)","Copy the token immediately — it is shown only once","Deploy the 1Password Connect Server using Docker with the credentials file (see https://developer.1password.com/docs/connect/get-started/)"],"credential_fields":[{"name":"api_key","label":"Connect Server Token","description":"The Bearer token issued for your 1Password Connect server. Used in the Authorization header.","secret":true,"placeholder":"eyJhbGciOiJFUzI1NiIsImtpZCI6..."}],"notes":["Requires a 1Password Teams or Business plan — not available on personal accounts","The Connect server must be self-hosted (Docker); the token authenticates against your self-hosted instance","The base URL of this API is your own Connect server URL, not a public Anthropic endpoint","Tokens expire after 30, 90, or 180 days and must be rotated","The token is shown only once at creation time — save it securely"],"test_endpoint":{"method":"GET","path":"/v1/vaults","expected_status":200,"description":"List all vaults accessible to the Connect server token"},"last_verified":"2026-03-02"},
